"""grants_v2_refresh

Revision ID: ac4d5e6f7081
Revises: ab2c3d4e5f61
Create Date: 2026-07-09

Adds production_stage + emerging_filmmaker to grant_opportunities and
replaces all rows with the 114 grants from the v2 source-of-truth database
(docs/data-sources/prodculator_grants_database_v2.html, `const G`).

Mapping (see _build_row):
  * fund_name -> title, source_name -> funding_body, amount -> max_amount,
    open_date -> application_opens, deadline -> application_deadline,
    source_url -> website_url, verified_at -> last_verified_at,
    stage -> production_stage, emerging_filmmaker -> emerging_filmmaker
  * structured v2 fields with no dedicated column (eligible_formats,
    genre_tags, grant_type, recurrence, nationality/co-production flags,
    USD amounts) are preserved as lines in the eligibility JSON list —
    single-format grants get the exact phrases ("short film only",
    "feature film only") that reports/builder.py's format filter matches
  * territory names are stored as canonical Territory labels;
    "Global" funds keep territory "Global" (not territory-matched by the
    report builder, by design)
  * status / days_until_deadline are computed against the fixed refresh
    date 2026-07-09 (rolling -> open, tbc -> opening_soon, dated deadlines
    open / closing_soon at <=56 days / closed), mirroring the original
    seed's point-in-time convention

Downgrade removes the rows and the two columns.
"""
from __future__ import annotations

import json
import uuid
from datetime import date, datetime, timezone

import sqlalchemy as sa
from alembic import op

revision = "ac4d5e6f7081"
down_revision = "ab2c3d4e5f61"
branch_labels = None
depends_on = None

_REFRESH_DATE = date(2026, 7, 9)
_CLOSING_SOON_DAYS = 56

_NEW_COLUMNS: list[tuple[str, sa.types.TypeEngine]] = [
    ("production_stage", sa.Text()),
    ("emerging_filmmaker", sa.Boolean()),
]

# Full accumulated grant_opportunities schema (0de65d194977), used only when
# the table is missing entirely (stamped DBs skipped the create migration).
_BASE_COLUMNS: list[tuple[str, sa.types.TypeEngine]] = [
    ("title", sa.Text()),
    ("territory", sa.Text()),
    ("funding_body", sa.Text()),
    ("max_amount", sa.Text()),
    ("currency", sa.Text()),
    ("application_opens", sa.Text()),
    ("application_deadline", sa.Text()),
    ("status", sa.Text()),
    ("days_until_deadline", sa.Integer()),
    ("eligibility", sa.JSON()),
    ("website_url", sa.Text()),
    ("data_source", sa.Text()),
    ("verified", sa.Boolean()),
    ("is_new", sa.Boolean()),
    ("created_at", sa.DateTime()),
    ("updated_at", sa.DateTime()),
    ("last_verified_at", sa.DateTime()),
]


def _status_and_days(open_date: str, deadline: str) -> tuple[str, int | None]:
    if deadline == "rolling":
        return "open", None
    if deadline.startswith("tbc"):
        return "opening_soon", None
    try:
        dl = date.fromisoformat(deadline)
    except ValueError:
        return "open", None
    days = (dl - _REFRESH_DATE).days
    try:
        opens = date.fromisoformat(open_date)
    except (TypeError, ValueError):
        opens = None
    if opens and opens > _REFRESH_DATE:
        return "opening_soon", days
    if days < 0:
        return "closed", None
    if days <= _CLOSING_SOON_DAYS:
        return "closing_soon", days
    return "open", days


def _eligibility_lines(src: dict) -> list[str]:
    lines = [src["eligibility"]]

    formats = src.get("eligible_formats") or []
    if formats:
        line = "Eligible formats: " + ", ".join(formats)
        # exact phrases reports/builder.py format-filters on
        if formats == ["short"]:
            line += " (short film only)"
        elif formats == ["feature"]:
            line += " (feature film only)"
        lines.append(line)

    genres = src.get("genre_tags") or []
    if genres:
        lines.append("Genres: " + ", ".join(genres))

    if src.get("grant_type"):
        lines.append(f"Grant type: {src['grant_type']}")
    if src.get("recurrence"):
        lines.append(f"Recurrence: {src['recurrence']}")
    if src.get("nationality_required"):
        lines.append("Nationality/residency restriction applies")
    if src.get("co_production_required"):
        lines.append("Co-production required")

    usd = src.get("amount_usd_approx")
    if isinstance(usd, int):
        lines.append(f"Typical award: ~USD {usd:,}")
    bmin, bmax = src.get("budget_min_usd"), src.get("budget_max_usd")
    if isinstance(bmin, int) or isinstance(bmax, int):
        lo = f"USD {bmin:,}" if isinstance(bmin, int) else "no minimum"
        hi = f"USD {bmax:,}" if isinstance(bmax, int) else "no maximum"
        lines.append(f"Project budget range: {lo} to {hi}")

    return lines


def _canonical_territory(name: str) -> str:
    from app.core.territories import resolve_territory

    t = resolve_territory(name)
    return t.label if t else name


def _build_row(src: dict, now: str) -> dict:
    territory = _canonical_territory(src["territory"])
    status, days = _status_and_days(src.get("open_date") or "", src.get("deadline") or "")
    return {
        "id": str(uuid.uuid5(uuid.NAMESPACE_URL, f"prodculator:grant:{territory}:{src['fund_name']}")),
        "title": src["fund_name"],
        "territory": territory,
        "funding_body": src.get("source_name"),
        "max_amount": src.get("amount"),
        "currency": src.get("currency"),
        "application_opens": src.get("open_date"),
        "application_deadline": src.get("deadline"),
        "status": status,
        "days_until_deadline": days,
        "eligibility": _eligibility_lines(src),
        "website_url": src.get("source_url"),
        "data_source": "prodculator_grants_database_v2",
        "verified": True,
        "is_new": False,
        "production_stage": src.get("stage"),
        "emerging_filmmaker": src.get("emerging_filmmaker"),
        "last_verified_at": src.get("verified_at"),
        "created_at": now,
        "updated_at": now,
    }


def upgrade() -> None:
    conn = op.get_bind()
    inspector = sa.inspect(conn)

    if "grant_opportunities" not in inspector.get_table_names():
        op.create_table(
            "grant_opportunities",
            sa.Column("id", sa.Text(), nullable=False),
            *[
                sa.Column(name, col_type, nullable=True)
                for name, col_type in _BASE_COLUMNS + _NEW_COLUMNS
            ],
            sa.PrimaryKeyConstraint("id"),
        )
    else:
        existing = {c["name"] for c in inspector.get_columns("grant_opportunities")}
        for name, col_type in _NEW_COLUMNS:
            if name not in existing:
                op.add_column(
                    "grant_opportunities", sa.Column(name, col_type, nullable=True)
                )

    table = sa.Table("grant_opportunities", sa.MetaData(), autoload_with=conn)
    now = datetime.now(timezone.utc).isoformat()
    rows = [_build_row(src, now) for src in _SOURCE_ROWS]

    assert len(rows) == 114, f"expected 114 rows, built {len(rows)}"
    assert len({r["id"] for r in rows}) == 114

    conn.execute(table.delete())
    conn.execute(table.insert(), rows)

    count = conn.execute(sa.text("SELECT COUNT(*) FROM grant_opportunities")).scalar()
    assert count == 114, f"post-insert count {count} != 114"


def downgrade() -> None:
    conn = op.get_bind()
    conn.execute(sa.text("DELETE FROM grant_opportunities"))
    inspector = sa.inspect(conn)
    existing = {c["name"] for c in inspector.get_columns("grant_opportunities")}
    for name, _ in _NEW_COLUMNS:
        if name in existing:
            op.drop_column("grant_opportunities", name)


